<?php
declare(strict_types=1);
namespace OneDB\Database;
use OneDB\Support\Environment;
use PDO;
final class ConnectionFactory
{
public static function makePdo(array $connection): PDO
{
$driver = strtolower((string)($connection['driver'] ?? 'mysql'));
$options = [
PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION,
PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
PDO::ATTR_EMULATE_PREPARES => false,
];
if ($driver === 'mysql' && defined('PDO::MYSQL_ATTR_USE_BUFFERED_QUERY')) {
$options[PDO::MYSQL_ATTR_USE_BUFFERED_QUERY] = false;
}
if ($driver === 'sqlite') {
$path = self::normalizeSqlitePath((string)($connection['path'] ?? ''));
$dsn = 'sqlite:' . $path;
$user = null;
$pass = null;
} else {
$host = trim((string)($connection['host'] ?? ''));
if ($host === '') {
$host = '127.0.0.1';
}
$defaultPort = $driver === 'pgsql' ? '5432' : '3306';
$port = trim((string)($connection['port'] ?? ''));
if ($port === '') {
$port = $defaultPort;
}
$db = (string)($connection['database'] ?? '');
$charset = (string)($connection['charset'] ?? 'utf8mb4');
$user = (string)($connection['username'] ?? '');
$pass = (string)($connection['password'] ?? '');
if ($driver === 'pgsql') {
$dsn = sprintf(
'pgsql:host=%s;port=%s%s',
$host,
$port,
$db !== '' ? ';dbname=' . $db : ''
);
} else {
$mysqlSocket = trim((string)($connection['unix_socket'] ?? $connection['socket'] ?? ''));
if ($mysqlSocket !== '') {
if ($db !== '') {
$dsn = sprintf('mysql:unix_socket=%s;dbname=%s;charset=%s', $mysqlSocket, $db, $charset);
} else {
$dsn = sprintf('mysql:unix_socket=%s;charset=%s', $mysqlSocket, $charset);
}
} else {
$dsn = self::buildMysqlHostDsn($host, $port, $db, $charset);
}
}
}
try {
$pdo = new PDO($dsn, $user, $pass, $options);
} catch (\PDOException $firstError) {
if (
$driver === 'mysql'
&& isset($host, $port, $db, $charset)
&& strcasecmp($host, 'localhost') === 0
&& trim((string)($connection['unix_socket'] ?? $connection['socket'] ?? '')) === ''
) {
$fallbackDsn = self::buildMysqlHostDsn('127.0.0.1', $port, $db, $charset);
$pdo = new PDO($fallbackDsn, $user, $pass, $options);
} else {
throw $firstError;
}
}
if (Environment::readonlyMode()) {
self::configureReadonlySession($pdo, $driver);
}
return $pdo;
}
private static function buildMysqlHostDsn(string $host, string $port, string $db, string $charset): string
{
if ($db !== '') {
return sprintf('mysql:host=%s;port=%s;dbname=%s;charset=%s', $host, $port, $db, $charset);
}
return sprintf('mysql:host=%s;port=%s;charset=%s', $host, $port, $charset);
}
private static function configureReadonlySession(PDO $pdo, string $driver): void
{
if ($driver === 'pgsql') {
$pdo->exec('SET default_transaction_read_only = on');
return;
}
if ($driver === 'mysql') {
$pdo->exec('SET SESSION TRANSACTION READ ONLY');
}
}
private static function normalizeSqlitePath(string $path): string
{
$candidate = trim($path);
if ($candidate === '') {
throw new \InvalidArgumentException('SQLite path is required.');
}
if ($candidate === ':memory:') {
return $candidate;
}
if (strpos($candidate, "\0") !== false) {
throw new \InvalidArgumentException('SQLite path is invalid.');
}
$rootRaw = trim((string)(getenv('ONEDB_SQLITE_ROOT') ?: ''));
if ($rootRaw === '') {
return $candidate;
}
$root = realpath($rootRaw);
if ($root === false) {
throw new \RuntimeException('Configured ONEDB_SQLITE_ROOT directory does not exist.');
}
$absoluteCandidate = self::resolveAbsolutePath($candidate);
$resolvedFile = realpath($absoluteCandidate);
if ($resolvedFile !== false) {
if (!self::pathStartsWith($resolvedFile, $root)) {
throw new \RuntimeException('SQLite path is outside allowed root.');
}
return $resolvedFile;
}
$parent = realpath(dirname($absoluteCandidate));
if ($parent === false || !self::pathStartsWith($parent, $root)) {
throw new \RuntimeException('SQLite path is outside allowed root.');
}
return $absoluteCandidate;
}
private static function resolveAbsolutePath(string $path): string
{
if (self::isAbsolutePath($path)) {
return $path;
}
$base = getcwd();
if ($base === false || $base === '') {
return $path;
}
return rtrim($base, DIRECTORY_SEPARATOR) . DIRECTORY_SEPARATOR . $path;
}
private static function isAbsolutePath(string $path): bool
{
if ($path === '') {
return false;
}
if ($path[0] === '/' || $path[0] === '\\') {
return true;
}
return (bool)preg_match('/^[a-zA-Z]:[\\\\\\/]/', $path);
}
private static function pathStartsWith(string $path, string $root): bool
{
$normalizedPath = rtrim(str_replace('\\', '/', $path), '/');
$normalizedRoot = rtrim(str_replace('\\', '/', $root), '/');
return $normalizedPath === $normalizedRoot || strpos($normalizedPath, $normalizedRoot . '/') === 0;
}
}

namespace OneDB\Database;
use PDO;
final class MetadataService
{
public static function listDatabases(array $connection): array
{
$driver = strtolower((string)($connection['driver'] ?? 'mysql'));
$pdo = ConnectionFactory::makePdo($connection);
if ($driver === 'sqlite') {
return ['main'];
}
$sql = $driver === 'pgsql'
? 'SELECT datname FROM pg_database WHERE datistemplate = false ORDER BY datname;'
: 'SHOW DATABASES;';
$rows = $pdo->query($sql)->fetchAll(PDO::FETCH_NUM);
return array_values(array_filter(array_map(
static fn (array $row): string => trim((string)($row[0] ?? '')),
$rows
)));
}
public static function listTables(array $connection): array
{
$driver = strtolower((string)($connection['driver'] ?? 'mysql'));
$pdo = ConnectionFactory::makePdo($connection);
if ($driver === 'sqlite') {
return self::listSqliteTables($pdo);
}
$sql = $driver === 'pgsql'
? "
SELECT
t.table_name AS name,
t.table_type AS type,
COUNT(c.column_name) AS column_count
FROM information_schema.tables t
LEFT JOIN information_schema.columns c
ON c.table_schema = t.table_schema
AND c.table_name = t.table_name
WHERE t.table_schema = 'public'
GROUP BY t.table_name, t.table_type
ORDER BY t.table_name;
"
: "
SELECT
t.TABLE_NAME AS name,
t.TABLE_TYPE AS type,
COUNT(c.COLUMN_NAME) AS column_count
FROM information_schema.tables t
LEFT JOIN information_schema.columns c
ON c.table_schema = t.table_schema
AND c.table_name = t.table_name
WHERE t.table_schema = DATABASE()
GROUP BY t.TABLE_NAME, t.TABLE_TYPE
ORDER BY t.TABLE_NAME;
";
$rows = $pdo->query($sql)->fetchAll(PDO::FETCH_ASSOC);
return array_values(array_filter(array_map(
static function (array $row): array {
$name = trim((string)($row['name'] ?? ''));
if ($name === '') {
return [];
}
$type = strtolower((string)($row['type'] ?? 'table'));
return [
'name' => $name,
'type' => strpos($type, 'view') !== false ? 'view' : 'table',
'columnCount' => (int)($row['column_count'] ?? 0),
];
},
$rows
)));
}
private static function listSqliteTables(PDO $pdo): array
{
try {
$rows = $pdo->query("
SELECT
m.name AS name,
m.type AS type,
COUNT(p.name) AS column_count
FROM sqlite_master m
LEFT JOIN pragma_table_info(m.name) p
WHERE m.type IN ('table', 'view')
AND m.name NOT LIKE 'sqlite_%'
GROUP BY m.name, m.type
ORDER BY m.name;
")->fetchAll(PDO::FETCH_ASSOC);
return array_values(array_filter(array_map(
static function (array $row): array {
$name = trim((string)($row['name'] ?? ''));
if ($name === '') {
return [];
}
return [
'name' => $name,
'type' => strtolower((string)($row['type'] ?? 'table')) === 'view' ? 'view' : 'table',
'columnCount' => (int)($row['column_count'] ?? 0),
];
},
$rows
)));
} catch (\Throwable $_) {
$tableRows = $pdo->query("
SELECT name, type
FROM sqlite_master
WHERE type IN ('table', 'view')
AND name NOT LIKE 'sqlite_%'
ORDER BY name;
")->fetchAll(PDO::FETCH_ASSOC);
$tables = [];
foreach ($tableRows as $row) {
$tableName = (string)($row['name'] ?? '');
if ($tableName === '') {
continue;
}
$pragmaRows = $pdo
->query('PRAGMA table_info(' . self::quoteIdentifier($tableName, 'sqlite') . ')')
->fetchAll(PDO::FETCH_ASSOC);
$tables[] = [
'name' => $tableName,
'type' => strtolower((string)($row['type'] ?? 'table')) === 'view' ? 'view' : 'table',
'columnCount' => count($pragmaRows),
];
}
return $tables;
}
}
public static function browseTable(array $payload): array
{
$connection = is_array($payload['connection'] ?? null) ? $payload['connection'] : [];
$table = trim((string)($payload['table'] ?? ''));
if ($table === '') {
throw new \InvalidArgumentException('Table is required.');
}
$page = max(1, (int)($payload['page'] ?? 1));
$perPage = max(1, min(200, (int)($payload['perPage'] ?? 25)));
$includeRowCount = !array_key_exists('includeRowCount', $payload) || (bool)$payload['includeRowCount'];
$includeInsights = (bool)($payload['includeInsights'] ?? false);
$driver = strtolower((string)($connection['driver'] ?? 'mysql'));
$pdo = ConnectionFactory::makePdo($connection);
$columns = self::describeTable($pdo, $connection, $table);
$columnMap = [];
foreach ($columns as $column) {
$columnMap[$column['name']] = true;
}
$bindings = [];
$whereParts = [];
$filters = is_array($payload['filters'] ?? null) ? $payload['filters'] : [];
foreach ($filters as $index => $filter) {
if (!is_array($filter)) {
continue;
}
$column = trim((string)($filter['column'] ?? ''));
$operator = strtolower(trim((string)($filter['operator'] ?? 'contains')));
$value = $filter['value'] ?? null;
if ($column === '' || !isset($columnMap[$column])) {
continue;
}
if (!in_array($operator, ['contains', 'eq', 'neq', 'gt', 'gte', 'lt', 'lte', 'starts_with', 'ends_with'], true)) {
continue;
}
$quotedColumn = self::quoteIdentifier($column, $driver);
$bindKey = ':filter_' . $index;
switch ($operator) {
case 'eq':
$whereParts[] = $quotedColumn . ' = ' . $bindKey;
$bindings[$bindKey] = $value;
break;
case 'neq':
$whereParts[] = $quotedColumn . ' != ' . $bindKey;
$bindings[$bindKey] = $value;
break;
case 'gt':
$whereParts[] = $quotedColumn . ' > ' . $bindKey;
$bindings[$bindKey] = $value;
break;
case 'gte':
$whereParts[] = $quotedColumn . ' >= ' . $bindKey;
$bindings[$bindKey] = $value;
break;
case 'lt':
$whereParts[] = $quotedColumn . ' < ' . $bindKey;
$bindings[$bindKey] = $value;
break;
case 'lte':
$whereParts[] = $quotedColumn . ' <= ' . $bindKey;
$bindings[$bindKey] = $value;
break;
case 'starts_with':
$whereParts[] = self::stringExpression($quotedColumn, $driver) . ' LIKE ' . $bindKey;
$bindings[$bindKey] = (string)$value . '%';
break;
case 'ends_with':
$whereParts[] = self::stringExpression($quotedColumn, $driver) . ' LIKE ' . $bindKey;
$bindings[$bindKey] = '%' . (string)$value;
break;
case 'contains':
default:
$whereParts[] = self::stringExpression($quotedColumn, $driver) . ' LIKE ' . $bindKey;
$bindings[$bindKey] = '%' . (string)$value . '%';
break;
}
}
$whereSql = $whereParts === [] ? '' : ' WHERE ' . implode(' AND ', $whereParts);
$sortPayload = is_array($payload['sort'] ?? null) ? $payload['sort'] : [];
$sortColumn = trim((string)($sortPayload['column'] ?? ''));
$sortDirection = strtolower((string)($sortPayload['direction'] ?? 'asc')) === 'desc' ? 'DESC' : 'ASC';
$orderSql = '';
if ($sortColumn !== '' && isset($columnMap[$sortColumn])) {
$orderSql = ' ORDER BY ' . self::quoteIdentifier($sortColumn, $driver) . ' ' . $sortDirection;
} elseif ($columns !== []) {
$primaryColumn = null;
foreach ($columns as $column) {
if ($column['isPrimary']) {
$primaryColumn = $column['name'];
break;
}
}
$defaultColumn = $primaryColumn ?? $columns[0]['name'];
$orderSql = ' ORDER BY ' . self::quoteIdentifier($defaultColumn, $driver) . ' ASC';
}
$qualifiedTable = self::quoteIdentifier($table, $driver);
$rowCount = null;
if ($includeRowCount) {
$countStmt = $pdo->prepare('SELECT COUNT(*) AS total_count FROM ' . $qualifiedTable . $whereSql);
foreach ($bindings as $key => $value) {
$countStmt->bindValue($key, $value);
}
try {
$countStmt->execute();
$rowCount = (int)($countStmt->fetchColumn() ?: 0);
} finally {
$countStmt->closeCursor();
}
}
$offset = ($page - 1) * $perPage;
$dataSql = 'SELECT * FROM ' . $qualifiedTable . $whereSql . $orderSql . ' LIMIT ' . $perPage . ' OFFSET ' . $offset;
$dataStmt = $pdo->prepare($dataSql);
foreach ($bindings as $key => $value) {
$dataStmt->bindValue($key, $value);
}
$startedAt = microtime(true);
try {
$dataStmt->execute();
$rows = $dataStmt->fetchAll(PDO::FETCH_ASSOC);
} finally {
$dataStmt->closeCursor();
}
$durationMs = (microtime(true) - $startedAt) * 1000;
$insights = null;
if ($includeInsights) {
$tableType = 'table';
if (is_array($payload['tableType'] ?? null)) {
$tableType = 'table';
} elseif (is_string($payload['tableType'] ?? null)) {
$tableType = strtolower((string)$payload['tableType']) === 'view' ? 'view' : 'table';
}
$insights = self::describeTableInsights($pdo, $connection, $table, $tableType);
}
return [
'ok' => true,
'kind' => 'browse_table',
'columns' => $columns,
'rows' => $rows,
'rowCount' => $rowCount,
'page' => $page,
'perPage' => $perPage,
'durationMs' => round($durationMs, 2),
'insights' => $insights,
];
}
private static function describeTable(PDO $pdo, array $connection, string $table): array
{
$driver = strtolower((string)($connection['driver'] ?? 'mysql'));
if ($driver === 'sqlite') {
$quotedTable = self::quoteIdentifier($table, $driver);
$columnsResult = $pdo->query('PRAGMA table_info(' . $quotedTable . ')')->fetchAll(PDO::FETCH_ASSOC);
$foreignResult = $pdo->query('PRAGMA foreign_key_list(' . $quotedTable . ')')->fetchAll(PDO::FETCH_ASSOC);
$foreignMap = [];
foreach ($foreignResult as $foreignRow) {
$foreignMap[(string)($foreignRow['from'] ?? '')] = [
'table' => (string)($foreignRow['table'] ?? ''),
'column' => (string)($foreignRow['to'] ?? ''),
];
}
$columns = [];
foreach ($columnsResult as $columnRow) {
$name = (string)($columnRow['name'] ?? '');
$foreign = $foreignMap[$name] ?? null;
$columns[] = [
'name' => $name,
'type' => (string)($columnRow['type'] ?? ''),
'extra' => '',
'isPrimary' => (int)($columnRow['pk'] ?? 0) === 1,
'nullable' => (int)($columnRow['notnull'] ?? 0) === 1 ? 'No' : 'Yes',
'isForeign' => $foreign !== null,
'foreignTable' => $foreign['table'] ?? null,
'foreignCol' => $foreign['column'] ?? null,
];
}
return $columns;
}
$tableBind = ':table_name';
if ($driver === 'pgsql') {
$columnsSql = "
SELECT
c.column_name AS name,
c.data_type AS data_type,
c.is_nullable AS is_nullable,
c.column_default AS column_default,
CASE WHEN pk.column_name IS NOT NULL THEN 'PRI' ELSE '' END AS column_key,
COALESCE(c.column_default, '') AS extra
FROM information_schema.columns c
LEFT JOIN (
SELECT kcu.column_name
FROM information_schema.table_constraints tc
INNER JOIN information_schema.key_column_usage kcu
ON tc.constraint_name = kcu.constraint_name
AND tc.table_schema = kcu.table_schema
WHERE tc.constraint_type = 'PRIMARY KEY'
AND tc.table_schema = 'public'
AND tc.table_name = {$tableBind}
) pk ON pk.column_name = c.column_name
WHERE c.table_schema = 'public'
AND c.table_name = {$tableBind}
ORDER BY c.ordinal_position;
";
$foreignKeysSql = "
SELECT
kcu.column_name AS column_name,
ccu.table_name AS referenced_table_name,
ccu.column_name AS referenced_column_name
FROM information_schema.table_constraints tc
INNER JOIN information_schema.key_column_usage kcu
ON tc.constraint_name = kcu.constraint_name
AND tc.table_schema = kcu.table_schema
INNER JOIN information_schema.constraint_column_usage ccu
ON ccu.constraint_name = tc.constraint_name
AND ccu.table_schema = tc.table_schema
WHERE tc.constraint_type = 'FOREIGN KEY'
AND tc.table_schema = 'public'
AND tc.table_name = {$tableBind};
";
} else {
$columnsSql = "
SELECT
COLUMN_NAME AS name,
COLUMN_TYPE AS data_type,
IS_NULLABLE AS is_nullable,
COLUMN_DEFAULT AS column_default,
COLUMN_KEY AS column_key,
EXTRA AS extra
FROM information_schema.columns
WHERE table_schema = DATABASE()
AND table_name = {$tableBind}
ORDER BY ORDINAL_POSITION;
";
$foreignKeysSql = "
SELECT
COLUMN_NAME AS column_name,
REFERENCED_TABLE_NAME AS referenced_table_name,
REFERENCED_COLUMN_NAME AS referenced_column_name
FROM information_schema.key_column_usage
WHERE table_schema = DATABASE()
AND table_name = {$tableBind}
AND referenced_table_name IS NOT NULL;
";
}
$columnsStmt = $pdo->prepare($columnsSql);
$columnsStmt->bindValue($tableBind, $table);
$columnsStmt->execute();
$columnRows = $columnsStmt->fetchAll(PDO::FETCH_ASSOC);
$foreignStmt = $pdo->prepare($foreignKeysSql);
$foreignStmt->bindValue($tableBind, $table);
$foreignStmt->execute();
$foreignRows = $foreignStmt->fetchAll(PDO::FETCH_ASSOC);
$foreignMap = [];
foreach ($foreignRows as $foreignRow) {
$foreignMap[(string)($foreignRow['column_name'] ?? '')] = [
'table' => (string)($foreignRow['referenced_table_name'] ?? ''),
'column' => (string)($foreignRow['referenced_column_name'] ?? ''),
];
}
$columns = [];
foreach ($columnRows as $columnRow) {
$name = (string)($columnRow['name'] ?? '');
$foreign = $foreignMap[$name] ?? null;
$nullableRaw = strtolower((string)($columnRow['is_nullable'] ?? ''));
$columns[] = [
'name' => $name,
'type' => (string)($columnRow['data_type'] ?? ''),
'extra' => (string)($columnRow['extra'] ?? $columnRow['column_default'] ?? ''),
'isPrimary' => strtoupper((string)($columnRow['column_key'] ?? '')) === 'PRI',
'nullable' => $nullableRaw === 'yes' ? 'Yes' : 'No',
'isForeign' => $foreign !== null,
'foreignTable' => $foreign['table'] ?? null,
'foreignCol' => $foreign['column'] ?? null,
];
}
return $columns;
}
private static function quoteIdentifier(string $name, string $driver): string
{
if ($driver === 'mysql') {
return '`' . str_replace('`', '``', $name) . '`';
}
return '"' . str_replace('"', '""', $name) . '"';
}
private static function stringExpression(string $quotedColumn, string $driver): string
{
if ($driver === 'mysql') {
return 'CAST(' . $quotedColumn . ' AS CHAR)';
}
return 'CAST(' . $quotedColumn . ' AS TEXT)';
}
private static function describeTableInsights(
PDO $pdo,
array $connection,
string $table,
string $tableType
): array {
$driver = strtolower((string)($connection['driver'] ?? 'mysql'));
return [
'indexes' => self::safeInsight(
static fn (): array => self::listTableIndexes($pdo, $driver, $table),
[]
),
'foreignKeys' => self::safeInsight(
static fn (): array => self::listForeignKeys($pdo, $driver, $table),
[]
),
'referencedBy' => self::safeInsight(
static fn (): array => self::listReferencedBy($pdo, $driver, $table),
[]
),
'viewDefinition' => $tableType === 'view'
? self::safeInsight(
static fn (): ?string => self::loadViewDefinition($pdo, $driver, $table),
null
)
: null,
'relatedRoutines' => self::safeInsight(
static fn (): array => self::listRelatedRoutines($pdo, $driver, $table),
[]
),
];
}
private static function safeInsight(callable $resolver, $fallback)
{
try {
return $resolver();
} catch (\Throwable $_) {
return $fallback;
}
}
private static function listTableIndexes(PDO $pdo, string $driver, string $table): array
{
if ($driver === 'sqlite') {
return self::listSqliteIndexes($pdo, $table);
}
if ($driver === 'pgsql') {
$stmt = $pdo->prepare("
SELECT
i.indexname AS index_name,
i.indexdef AS index_definition
FROM pg_indexes i
WHERE i.schemaname = 'public'
AND i.tablename = :table_name
ORDER BY i.indexname;
");
$stmt->bindValue(':table_name', $table);
$stmt->execute();
$rows = $stmt->fetchAll(PDO::FETCH_ASSOC);
return array_values(array_filter(array_map(
static function (array $row): array {
$indexName = trim((string)($row['index_name'] ?? ''));
if ($indexName === '') {
return [];
}
$definition = trim((string)($row['index_definition'] ?? ''));
$isUnique = stripos($definition, 'UNIQUE INDEX') !== false;
$columns = [];
if (preg_match('/\((.+)\)\s*$/', $definition, $matches) === 1) {
$columnParts = explode(',', (string)($matches[1] ?? ''));
foreach ($columnParts as $part) {
$clean = trim((string)$part);
if ($clean !== '') {
$columns[] = $clean;
}
}
}
return [
'name' => $indexName,
'unique' => $isUnique,
'columns' => $columns,
'definition' => $definition,
];
},
$rows
)));
}
$stmt = $pdo->prepare("
SELECT
s.INDEX_NAME AS index_name,
MIN(s.NON_UNIQUE) AS non_unique,
GROUP_CONCAT(s.COLUMN_NAME ORDER BY s.SEQ_IN_INDEX SEPARATOR ',') AS column_list
FROM information_schema.statistics s
WHERE s.table_schema = DATABASE()
AND s.table_name = :table_name
GROUP BY s.INDEX_NAME
ORDER BY s.INDEX_NAME;
");
$stmt->bindValue(':table_name', $table);
$stmt->execute();
$rows = $stmt->fetchAll(PDO::FETCH_ASSOC);
return array_values(array_filter(array_map(
static function (array $row): array {
$indexName = trim((string)($row['index_name'] ?? ''));
if ($indexName === '') {
return [];
}
$columnList = trim((string)($row['column_list'] ?? ''));
$columns = $columnList === '' ? [] : array_map('trim', explode(',', $columnList));
return [
'name' => $indexName,
'unique' => (int)($row['non_unique'] ?? 1) === 0,
'columns' => $columns,
'definition' => null,
];
},
$rows
)));
}
private static function listSqliteIndexes(PDO $pdo, string $table): array
{
$quoted = self::quoteIdentifier($table, 'sqlite');
$indexRows = $pdo->query('PRAGMA index_list(' . $quoted . ')')->fetchAll(PDO::FETCH_ASSOC);
$indexes = [];
foreach ($indexRows as $indexRow) {
$indexName = trim((string)($indexRow['name'] ?? ''));
if ($indexName === '') {
continue;
}
$indexInfo = $pdo
->query('PRAGMA index_info(' . self::quoteIdentifier($indexName, 'sqlite') . ')')
->fetchAll(PDO::FETCH_ASSOC);
$columns = [];
foreach ($indexInfo as $columnRow) {
$columnName = trim((string)($columnRow['name'] ?? ''));
if ($columnName !== '') {
$columns[] = $columnName;
}
}
$indexes[] = [
'name' => $indexName,
'unique' => (int)($indexRow['unique'] ?? 0) === 1,
'columns' => $columns,
'definition' => null,
];
}
return $indexes;
}
private static function listForeignKeys(PDO $pdo, string $driver, string $table): array
{
if ($driver === 'sqlite') {
$rows = $pdo
->query('PRAGMA foreign_key_list(' . self::quoteIdentifier($table, 'sqlite') . ')')
->fetchAll(PDO::FETCH_ASSOC);
return array_values(array_filter(array_map(
static function (array $row): array {
$from = trim((string)($row['from'] ?? ''));
$toTable = trim((string)($row['table'] ?? ''));
$toColumn = trim((string)($row['to'] ?? ''));
if ($from === '' || $toTable === '' || $toColumn === '') {
return [];
}
return [
'constraint' => 'fk_' . $from,
'column' => $from,
'referencedTable' => $toTable,
'referencedColumn' => $toColumn,
];
},
$rows
)));
}
if ($driver === 'pgsql') {
$stmt = $pdo->prepare("
SELECT
tc.constraint_name AS constraint_name,
kcu.column_name AS column_name,
ccu.table_name AS referenced_table_name,
ccu.column_name AS referenced_column_name
FROM information_schema.table_constraints tc
INNER JOIN information_schema.key_column_usage kcu
ON tc.constraint_name = kcu.constraint_name
AND tc.table_schema = kcu.table_schema
INNER JOIN information_schema.constraint_column_usage ccu
ON ccu.constraint_name = tc.constraint_name
AND ccu.table_schema = tc.table_schema
WHERE tc.constraint_type = 'FOREIGN KEY'
AND tc.table_schema = 'public'
AND tc.table_name = :table_name
ORDER BY tc.constraint_name, kcu.ordinal_position;
");
$stmt->bindValue(':table_name', $table);
$stmt->execute();
$rows = $stmt->fetchAll(PDO::FETCH_ASSOC);
} else {
$stmt = $pdo->prepare("
SELECT
CONSTRAINT_NAME AS constraint_name,
COLUMN_NAME AS column_name,
REFERENCED_TABLE_NAME AS referenced_table_name,
REFERENCED_COLUMN_NAME AS referenced_column_name
FROM information_schema.key_column_usage
WHERE table_schema = DATABASE()
AND table_name = :table_name
AND REFERENCED_TABLE_NAME IS NOT NULL
ORDER BY CONSTRAINT_NAME, ORDINAL_POSITION;
");
$stmt->bindValue(':table_name', $table);
$stmt->execute();
$rows = $stmt->fetchAll(PDO::FETCH_ASSOC);
}
return array_values(array_filter(array_map(
static function (array $row): array {
$column = trim((string)($row['column_name'] ?? ''));
$toTable = trim((string)($row['referenced_table_name'] ?? ''));
$toColumn = trim((string)($row['referenced_column_name'] ?? ''));
if ($column === '' || $toTable === '' || $toColumn === '') {
return [];
}
return [
'constraint' => trim((string)($row['constraint_name'] ?? '')),
'column' => $column,
'referencedTable' => $toTable,
'referencedColumn' => $toColumn,
];
},
$rows
)));
}
private static function listReferencedBy(PDO $pdo, string $driver, string $table): array
{
if ($driver === 'sqlite') {
$tables = $pdo->query("
SELECT name
FROM sqlite_master
WHERE type = 'table'
AND name NOT LIKE 'sqlite_%'
ORDER BY name;
")->fetchAll(PDO::FETCH_ASSOC);
$relations = [];
foreach ($tables as $tableRow) {
$fromTable = trim((string)($tableRow['name'] ?? ''));
if ($fromTable === '') {
continue;
}
$fkRows = $pdo
->query('PRAGMA foreign_key_list(' . self::quoteIdentifier($fromTable, 'sqlite') . ')')
->fetchAll(PDO::FETCH_ASSOC);
foreach ($fkRows as $fkRow) {
$toTable = trim((string)($fkRow['table'] ?? ''));
if ($toTable !== $table) {
continue;
}
$fromColumn = trim((string)($fkRow['from'] ?? ''));
$toColumn = trim((string)($fkRow['to'] ?? ''));
if ($fromColumn === '' || $toColumn === '') {
continue;
}
$relations[] = [
'constraint' => 'fk_' . $fromTable . '_' . $fromColumn,
'table' => $fromTable,
'column' => $fromColumn,
'targetColumn' => $toColumn,
];
}
}
return $relations;
}
if ($driver === 'pgsql') {
$stmt = $pdo->prepare("
SELECT
tc.constraint_name AS constraint_name,
kcu.table_name AS table_name,
kcu.column_name AS column_name,
ccu.column_name AS referenced_column_name
FROM information_schema.table_constraints tc
INNER JOIN information_schema.key_column_usage kcu
ON tc.constraint_name = kcu.constraint_name
AND tc.table_schema = kcu.table_schema
INNER JOIN information_schema.constraint_column_usage ccu
ON ccu.constraint_name = tc.constraint_name
AND ccu.table_schema = tc.table_schema
WHERE tc.constraint_type = 'FOREIGN KEY'
AND tc.table_schema = 'public'
AND ccu.table_name = :table_name
ORDER BY kcu.table_name, tc.constraint_name, kcu.ordinal_position;
");
$stmt->bindValue(':table_name', $table);
$stmt->execute();
$rows = $stmt->fetchAll(PDO::FETCH_ASSOC);
} else {
$stmt = $pdo->prepare("
SELECT
CONSTRAINT_NAME AS constraint_name,
TABLE_NAME AS table_name,
COLUMN_NAME AS column_name,
REFERENCED_COLUMN_NAME AS referenced_column_name
FROM information_schema.key_column_usage
WHERE table_schema = DATABASE()
AND REFERENCED_TABLE_NAME = :table_name
ORDER BY TABLE_NAME, CONSTRAINT_NAME, ORDINAL_POSITION;
");
$stmt->bindValue(':table_name', $table);
$stmt->execute();
$rows = $stmt->fetchAll(PDO::FETCH_ASSOC);
}
return array_values(array_filter(array_map(
static function (array $row): array {
$fromTable = trim((string)($row['table_name'] ?? ''));
$fromColumn = trim((string)($row['column_name'] ?? ''));
$targetColumn = trim((string)($row['referenced_column_name'] ?? ''));
if ($fromTable === '' || $fromColumn === '' || $targetColumn === '') {
return [];
}
return [
'constraint' => trim((string)($row['constraint_name'] ?? '')),
'table' => $fromTable,
'column' => $fromColumn,
'targetColumn' => $targetColumn,
];
},
$rows
)));
}
private static function loadViewDefinition(PDO $pdo, string $driver, string $viewName): ?string
{
if ($driver === 'sqlite') {
$stmt = $pdo->prepare("
SELECT sql
FROM sqlite_master
WHERE type = 'view'
AND name = :view_name
LIMIT 1;
");
$stmt->bindValue(':view_name', $viewName);
try {
$stmt->execute();
$value = $stmt->fetchColumn();
return is_string($value) && trim($value) !== '' ? trim($value) : null;
} finally {
$stmt->closeCursor();
}
}
if ($driver === 'pgsql') {
$stmt = $pdo->prepare("
SELECT view_definition
FROM information_schema.views
WHERE table_schema = 'public'
AND table_name = :view_name
LIMIT 1;
");
$stmt->bindValue(':view_name', $viewName);
try {
$stmt->execute();
$value = $stmt->fetchColumn();
return is_string($value) && trim($value) !== '' ? trim($value) : null;
} finally {
$stmt->closeCursor();
}
}
$stmt = $pdo->prepare("
SELECT view_definition
FROM information_schema.views
WHERE table_schema = DATABASE()
AND table_name = :view_name
LIMIT 1;
");
$stmt->bindValue(':view_name', $viewName);
try {
$stmt->execute();
$value = $stmt->fetchColumn();
return is_string($value) && trim($value) !== '' ? trim($value) : null;
} finally {
$stmt->closeCursor();
}
}
private static function listRelatedRoutines(PDO $pdo, string $driver, string $table): array
{
if ($driver === 'sqlite') {
return [];
}
$needle = '%' . $table . '%';
if ($driver === 'pgsql') {
$stmt = $pdo->prepare("
SELECT
routine_name,
routine_type
FROM information_schema.routines
WHERE specific_schema = 'public'
AND COALESCE(routine_definition, '') ILIKE :needle
ORDER BY routine_type, routine_name
LIMIT 50;
");
$stmt->bindValue(':needle', $needle);
$stmt->execute();
$rows = $stmt->fetchAll(PDO::FETCH_ASSOC);
} else {
$stmt = $pdo->prepare("
SELECT
ROUTINE_NAME AS routine_name,
ROUTINE_TYPE AS routine_type
FROM information_schema.routines
WHERE ROUTINE_SCHEMA = DATABASE()
AND COALESCE(ROUTINE_DEFINITION, '') LIKE :needle
ORDER BY ROUTINE_TYPE, ROUTINE_NAME
LIMIT 50;
");
$stmt->bindValue(':needle', $needle);
$stmt->execute();
$rows = $stmt->fetchAll(PDO::FETCH_ASSOC);
}
return array_values(array_filter(array_map(
static function (array $row): array {
$name = trim((string)($row['routine_name'] ?? ''));
if ($name === '') {
return [];
}
return [
'name' => $name,
'type' => strtoupper(trim((string)($row['routine_type'] ?? 'ROUTINE'))),
];
},
$rows
)));
}
}

namespace OneDB\Database;
use OneDB\Support\Environment;
use PDO;
final class QueryService
{
public static function execute(array $connection, string $sql): array
{
$pdo = ConnectionFactory::makePdo($connection);
$stmt = $pdo->prepare($sql);
$startedAt = microtime(true);
$stmt->execute();
$durationMs = (microtime(true) - $startedAt) * 1000;
if ($stmt->columnCount() === 0) {
return [
'ok' => true,
'kind' => 'mutation',
'affectedRows' => $stmt->rowCount(),
'durationMs' => round($durationMs, 2),
];
}
$maxRows = Environment::maxResultRows();
$rows = [];
$truncated = false;
$rowCount = 0;
$columns = [];
while (($row = $stmt->fetch(PDO::FETCH_ASSOC)) !== false) {
if ($rowCount >= $maxRows) {
$truncated = true;
break;
}
if ($rowCount === 0 && is_array($row)) {
$columns = array_map('strval', array_keys($row));
}
$rows[] = $row;
$rowCount++;
}
if ($columns === []) {
for ($index = 0; $index < $stmt->columnCount(); $index++) {
$meta = $stmt->getColumnMeta($index);
if (is_array($meta)) {
$columns[] = (string)($meta['name'] ?? '');
}
}
}
return [
'ok' => true,
'kind' => 'result_set',
'columns' => $columns,
'rows' => $rows,
'rowCount' => $rowCount,
'durationMs' => round($durationMs, 2),
'truncated' => $truncated,
'maxRows' => $maxRows,
];
}
}

namespace OneDB\Database;
final class ReadOnlySqlGuard
{
public static function hasSingleStatement(string $sql): bool
{
$inspected = self::normalizeSqlForInspection($sql);
if ($inspected === '') {
return false;
}
return preg_match('/;\s*\S/s', $inspected) !== 1;
}
public static function isReadOnly(string $sql): bool
{
$inspected = self::normalizeSqlForInspection($sql);
if ($inspected === '') {
return false;
}
$allowed = [
'select',
'show',
'describe',
'desc',
'explain',
'with',
'pragma',
];
$firstToken = strtolower((string)strtok($inspected, " \t\n\r\0\x0B"));
if (!in_array($firstToken, $allowed, true)) {
return false;
}
if (preg_match('/\b(insert|update|delete|merge|replace|upsert|create|alter|drop|truncate|grant|revoke|comment|attach|detach|copy)\b/i', $inspected)) {
return false;
}
if (preg_match('/\binto\s+(outfile|dumpfile)\b/i', $inspected)) {
return false;
}
return true;
}
private static function normalizeSqlForInspection(string $sql): string
{
$normalized = '';
$length = strlen($sql);
$inSingle = false;
$inDouble = false;
$inBacktick = false;
$inLineComment = false;
$inBlockComment = false;
for ($index = 0; $index < $length; $index++) {
$char = $sql[$index];
$next = $index + 1 < $length ? $sql[$index + 1] : '';
$prev = $index > 0 ? $sql[$index - 1] : '';
if ($inLineComment) {
if ($char === "\n") {
$inLineComment = false;
$normalized .= ' ';
}
continue;
}
if ($inBlockComment) {
if ($char === '*' && $next === '/') {
$index++;
$inBlockComment = false;
$normalized .= ' ';
}
continue;
}
if (!$inSingle && !$inDouble && !$inBacktick) {
if ($char === '-' && $next === '-') {
$inLineComment = true;
$index++;
continue;
}
if ($char === '/' && $next === '*') {
$inBlockComment = true;
$index++;
continue;
}
}
if (!$inDouble && !$inBacktick && $char === "'") {
if ($inSingle && $next === "'") {
$index++;
continue;
}
if (!$inSingle || $prev !== '\\') {
$inSingle = !$inSingle;
}
continue;
}
if (!$inSingle && !$inBacktick && $char === '"') {
if ($inDouble && $next === '"') {
$index++;
continue;
}
if (!$inDouble || $prev !== '\\') {
$inDouble = !$inDouble;
}
continue;
}
if (!$inSingle && !$inDouble && $char === '`') {
$inBacktick = !$inBacktick;
continue;
}
if ($inSingle || $inDouble || $inBacktick) {
continue;
}
$normalized .= $char;
}
return trim(strtolower($normalized));
}
}

namespace OneDB\Http;
use JsonException;
use OneDB\Support\Environment;
final class ApiRequest
{
private const ACTION_PATTERN = '/^[a-z][a-z0-9_]*$/';
public static function isApiRequest(): bool
{
if (isset($_GET['action']) || isset($_GET['api'])) {
return true;
}
$uri = (string)($_SERVER['REQUEST_URI'] ?? '');
$path = (string)parse_url($uri, PHP_URL_PATH);
return $path === '/api' || strpos($path, '/api/') === 0;
}
public static function resolveAction(): string
{
if (isset($_GET['action'])) {
return self::normalizeAction((string)$_GET['action']);
}
if (isset($_GET['api'])) {
return self::normalizeAction((string)$_GET['api']);
}
$uri = (string)($_SERVER['REQUEST_URI'] ?? '');
$path = trim((string)parse_url($uri, PHP_URL_PATH), '/');
if ($path === 'api') {
return '';
}
if (strpos($path, 'api/') === 0) {
return self::normalizeAction((string)substr($path, 4));
}
return '';
}
public static function readJson(): array
{
self::assertJsonBodyAllowed();
$raw = file_get_contents('php://input');
if ($raw === false || trim($raw) === '') {
return [];
}
if (strlen($raw) > Environment::maxBodyBytes()) {
throw new HttpException('Request payload is too large.', 413);
}
try {
$data = json_decode($raw, true, 512, JSON_THROW_ON_ERROR);
} catch (JsonException $e) {
throw new HttpException('Invalid JSON payload: ' . $e->getMessage(), 400);
}
if (!is_array($data)) {
throw new HttpException('JSON payload must be an object.', 400);
}
return $data;
}
private static function assertJsonBodyAllowed(): void
{
$method = strtoupper((string)($_SERVER['REQUEST_METHOD'] ?? 'GET'));
if (!in_array($method, ['POST', 'PUT', 'PATCH', 'DELETE'], true)) {
return;
}
$contentLength = (int)($_SERVER['CONTENT_LENGTH'] ?? 0);
if ($contentLength > Environment::maxBodyBytes()) {
throw new HttpException('Request payload is too large.', 413);
}
$contentType = strtolower((string)($_SERVER['CONTENT_TYPE'] ?? ''));
if ($contentType !== '' && strpos($contentType, 'application/json') === false) {
throw new HttpException('Content-Type must be application/json.', 415);
}
}
private static function normalizeAction(string $action): string
{
$normalized = trim(strtolower($action));
if ($normalized === '') {
return '';
}
return preg_match(self::ACTION_PATTERN, $normalized) === 1 ? $normalized : '';
}
}

namespace OneDB\Http;
use OneDB\Support\Environment;
final class CorsPolicy
{
public static function sendDevelopmentHeaders(): void
{
$origin = (string)($_SERVER['HTTP_ORIGIN'] ?? '');
$allowed = Environment::allowedOrigins();
header('Vary: Origin');
if ($origin !== '' && in_array($origin, $allowed, true)) {
header('Access-Control-Allow-Origin: ' . $origin);
header('Access-Control-Allow-Credentials: true');
}
header('Access-Control-Allow-Headers: Content-Type, X-CSRF-Token');
header('Access-Control-Allow-Methods: GET, POST, PUT, PATCH, DELETE, OPTIONS');
}
}

namespace OneDB\Http;
use RuntimeException;
final class HttpException extends RuntimeException
{
private $statusCode;
public function __construct(string $message, int $statusCode = 400)
{
parent::__construct($message);
$this->statusCode = $statusCode;
}
public function statusCode(): int
{
return $this->statusCode;
}
}

namespace OneDB\Http;
use OneDB\Support\DebugTelemetry;
final class JsonResponse
{
public static function send(array $payload, int $status = 200): void
{
http_response_code($status);
DebugTelemetry::appendResponseHeaders();
header('Cache-Control: no-store, no-cache, must-revalidate, max-age=0');
header('Pragma: no-cache');
header('X-Content-Type-Options: nosniff');
header('X-Frame-Options: DENY');
header('Referrer-Policy: no-referrer');
header('Content-Type: application/json; charset=utf-8');
echo json_encode($payload, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);
}
}

namespace OneDB\Http;
final class SessionCsrf
{
private const CSRF_KEY = 'onedb_csrf_token';
public static function bootSession(): void
{
if (session_status() === PHP_SESSION_ACTIVE) {
return;
}
session_start([
'cookie_httponly' => true,
'cookie_samesite' => 'Lax',
'cookie_secure' => self::isHttpsRequest(),
'use_strict_mode' => true,
]);
}
public static function token(): string
{
if (!isset($_SESSION[self::CSRF_KEY])) {
$_SESSION[self::CSRF_KEY] = bin2hex(random_bytes(24));
}
return (string)$_SESSION[self::CSRF_KEY];
}
public static function requireValidToken(): void
{
$method = strtoupper((string)($_SERVER['REQUEST_METHOD'] ?? 'GET'));
if (!in_array($method, ['POST', 'PUT', 'PATCH', 'DELETE'], true)) {
return;
}
$token = (string)($_SERVER['HTTP_X_CSRF_TOKEN'] ?? '');
if ($token === '' || !hash_equals(self::token(), $token)) {
throw new HttpException('CSRF validation failed.', 403);
}
}
private static function isHttpsRequest(): bool
{
if (!empty($_SERVER['HTTPS']) && strtolower((string)$_SERVER['HTTPS']) !== 'off') {
return true;
}
$forwardedProto = strtolower((string)($_SERVER['HTTP_X_FORWARDED_PROTO'] ?? ''));
return $forwardedProto === 'https';
}
}

namespace OneDB;
use OneDB\Database\ConnectionFactory;
use OneDB\Database\MetadataService;
use OneDB\Database\QueryService;
use OneDB\Database\ReadOnlySqlGuard;
use OneDB\Http\ApiRequest;
use OneDB\Http\CorsPolicy;
use OneDB\Http\HttpException;
use OneDB\Http\JsonResponse;
use OneDB\Http\SessionCsrf;
use OneDB\Support\Environment;
use OneDB\Support\ErrorResponder;
use OneDB\Support\UploadLimits;
use OneDB\Support\DebugTelemetry;
use PDOException;
use Throwable;
final class Runtime
{
public static function dispatch(): bool
{
if (!ApiRequest::isApiRequest()) {
return false;
}
DebugTelemetry::beginRequest();
$statusCode = 200;
$action = '';
try {
SessionCsrf::bootSession();
CorsPolicy::sendDevelopmentHeaders();
if (($_SERVER['REQUEST_METHOD'] ?? 'GET') === 'OPTIONS') {
$statusCode = 204;
http_response_code($statusCode);
return true;
}
$action = ApiRequest::resolveAction();
DebugTelemetry::setAction($action);
if ($action === '') {
$statusCode = 400;
JsonResponse::send(
ErrorResponder::fromMessage('Missing action parameter.', $statusCode, 'missing_action'),
$statusCode
);
return true;
}
try {
self::dispatchAction($action);
$status = http_response_code();
$statusCode = is_int($status) && $status > 0 ? $status : 200;
} catch (HttpException $e) {
$statusCode = $e->statusCode();
JsonResponse::send(ErrorResponder::fromThrowable($e, $statusCode, $action), $statusCode);
} catch (PDOException $e) {
$statusCode = 500;
JsonResponse::send(ErrorResponder::fromThrowable($e, $statusCode, $action), $statusCode);
} catch (Throwable $e) {
$statusCode = 500;
JsonResponse::send(ErrorResponder::fromThrowable($e, $statusCode, $action), $statusCode);
}
return true;
} finally {
$status = http_response_code();
if (is_int($status) && $status > 0) {
$statusCode = $status;
}
DebugTelemetry::logRequest($statusCode);
}
}
private static function dispatchAction(string $action): void
{
switch ($action) {
case 'csrf':
self::requireMethod(['GET']);
JsonResponse::send(['ok' => true, 'token' => SessionCsrf::token()]);
return;
case 'ping':
self::requireMethod(['GET']);
JsonResponse::send([
'ok' => true,
'time' => gmdate('c'),
'php' => PHP_VERSION,
'readonly' => Environment::readonlyMode(),
]);
return;
case 'upload_limits':
self::requireMethod(['GET']);
JsonResponse::send([
'ok' => true,
'limits' => UploadLimits::collect(),
]);
return;
case 'test_connection':
self::requireMethod(['POST']);
SessionCsrf::requireValidToken();
$payload = ApiRequest::readJson();
$pdo = ConnectionFactory::makePdo(self::connectionPayload($payload));
$pdo->query('SELECT 1');
JsonResponse::send(['ok' => true, 'message' => 'Connection successful.']);
return;
case 'list_databases':
self::requireMethod(['POST']);
SessionCsrf::requireValidToken();
$payload = ApiRequest::readJson();
JsonResponse::send([
'ok' => true,
'databases' => MetadataService::listDatabases(self::connectionPayload($payload)),
]);
return;
case 'list_tables':
self::requireMethod(['POST']);
SessionCsrf::requireValidToken();
$payload = ApiRequest::readJson();
JsonResponse::send([
'ok' => true,
'tables' => MetadataService::listTables(self::connectionPayload($payload)),
]);
return;
case 'browse_table':
self::requireMethod(['POST']);
SessionCsrf::requireValidToken();
JsonResponse::send(MetadataService::browseTable(ApiRequest::readJson()));
return;
case 'query':
self::requireMethod(['POST']);
SessionCsrf::requireValidToken();
self::handleQueryAction(ApiRequest::readJson());
return;
default:
JsonResponse::send(
ErrorResponder::fromMessage('Unsupported action.', 404, 'unsupported_action', $action),
404
);
return;
}
}
private static function handleQueryAction(array $payload): void
{
$sql = trim((string)($payload['sql'] ?? ''));
if ($sql === '') {
JsonResponse::send(
ErrorResponder::fromMessage('SQL is required.', 400, 'missing_sql', 'query'),
400
);
return;
}
if (!ReadOnlySqlGuard::hasSingleStatement($sql)) {
JsonResponse::send(
ErrorResponder::fromMessage(
'Only a single SQL statement is allowed per request.',
400,
'multiple_statements_not_allowed',
'query'
),
400
);
return;
}
if (Environment::readonlyMode() && !ReadOnlySqlGuard::isReadOnly($sql)) {
JsonResponse::send(
ErrorResponder::fromMessage(
'Readonly mode allows only read queries.',
403,
'readonly_violation',
'query'
),
403
);
return;
}
$result = QueryService::execute(self::connectionPayload($payload), $sql);
JsonResponse::send($result);
}
private static function connectionPayload(array $payload): array
{
return is_array($payload['connection'] ?? null) ? $payload['connection'] : [];
}
private static function requireMethod(array $allowed): void
{
$method = strtoupper((string)($_SERVER['REQUEST_METHOD'] ?? 'GET'));
$normalizedAllowed = array_map('strtoupper', $allowed);
if (!in_array($method, $normalizedAllowed, true)) {
throw new HttpException('HTTP method not allowed for this action.', 405);
}
}
}

namespace OneDB\Support;
final class DebugTelemetry
{
private static ?float $startedAt = null;
private static string $action = '';
public static function beginRequest(): void
{
self::$startedAt = microtime(true);
self::$action = '';
}
public static function setAction(string $action): void
{
self::$action = trim($action);
}
public static function appendResponseHeaders(): void
{
if (!Environment::debugMode()) {
return;
}
header('X-OneDB-Debug: 1');
header('X-OneDB-Request-Duration-Ms: ' . self::durationMs());
if (self::$action !== '') {
header('X-OneDB-Action: ' . self::$action);
}
}
public static function logRequest(int $statusCode): void
{
if (!Environment::debugMode()) {
return;
}
$method = strtoupper((string)($_SERVER['REQUEST_METHOD'] ?? 'GET'));
$uri = (string)($_SERVER['REQUEST_URI'] ?? '/');
$action = self::$action !== '' ? self::$action : '-';
$duration = self::durationMs();
$line = sprintf(
'[OneDB] method=%s uri=%s action=%s status=%d duration_ms=%.2f',
$method,
$uri,
$action,
$statusCode,
$duration
